import fs from 'fs';
import path from 'path';
import { parseMarkdownToInstructionData, serializeInstructionData } from '../lib/markdown';

const mainMdPath = path.join\(process.cwd\(\), 'data', 'project', 'main.md'\);

console.log\('Читаем файл:', mainMdPath\);
const content = fs.readFileSync\(mainMdPath, 'utf-8'\);

console.log\('Парсим и очищаем...'\);
const data = parseMarkdownToInstructionData\(content\);

console.log\('Сериализуем обратно...'\);
const cleaned = serializeInstructionData\(data\);

console.log\('Сохраняем...'\);
fs.writeFileSync\(mainMdPath, cleaned, 'utf-8'\);

console.log\('✅ Готово! Файл очищен от JSX-тегов.'\);
EOF)
